mapper.select:
SELECT id, user_id, order_number, order_status, subtotal, discount_amount, tax_amount, shipping_fee, total_amount, coupon_id, created_at, updated_at
FROM orders
WHERE id = #{id}

SELECT id, user_id, order_number, order_status, subtotal, discount_amount, tax_amount, shipping_fee, total_amount, coupon_id, created_at, updated_at
FROM orders
WHERE user_id = #{userId}
ORDER BY created_at DESC
LIMIT #{limit}

SELECT id, user_id, order_number, order_status, subtotal, discount_amount, tax_amount, shipping_fee, total_amount, coupon_id, created_at, updated_at
FROM orders


    AND id < #{lastId}


ORDER BY id DESC
LIMIT #{limit}

SELECT id, user_id, order_number, order_status, subtotal, discount_amount, tax_amount, shipping_fee, total_amount, coupon_id, created_at, updated_at
FROM orders


    AND user_id = #{userId}


    AND order_status = #{status}


    AND created_at >= #{fromDate}


    AND created_at <= #{toDate}


ORDER BY created_at DESC
LIMIT 1000
